import AuditLog from "../models/auditLogModel.js";
import AuditLogExport from "../models/auditLogExportModel.js";
import { dataExportQueue } from "../services/queueService.js";
import {
  AUDIT_EXPORT_DIRECTORY,
  buildAuditLogFilter,
  streamCsvExport,
  streamXlsxExport,
} from "../services/auditLogExportService.js";
import { sendSuccess, sendError } from "../utils/responseHandler.js";
import fs from "fs";
import path from "path";

const LARGE_EXPORT_THRESHOLD = 10000;
const EXPORT_TTL_MS = 24 * 60 * 60 * 1000;

const parseFilters = (query, organizationId) => {
  const { action, startDate, endDate } = query;
  if (startDate && Number.isNaN(new Date(startDate).getTime())) {
    throw new Error("Invalid startDate.");
  }
  if (endDate && Number.isNaN(new Date(endDate).getTime())) {
    throw new Error("Invalid endDate.");
  }
  return buildAuditLogFilter({ organizationId, action, startDate, endDate });
};

/**
 * ✅ Get Audit Logs for an Organization (Admin/Owner only)
 * GET /api/organization/:id/audit-logs
 */
export const getOrganizationAuditLogs = async (req, res) => {
  try {
    const organizationId = req.params.id;
    const { format, page = 1, limit = 20 } = req.query;
    if (format && !["csv", "xlsx"].includes(format)) {
      return sendError(res, 400, "Export format must be csv or xlsx.");
    }

    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);
    if (
      !Number.isInteger(pageNum) ||
      pageNum < 1 ||
      !Number.isInteger(limitNum) ||
      limitNum < 1
    ) {
      return sendError(res, 400, "page and limit must be positive integers.");
    }
    const skip = (pageNum - 1) * limitNum;
    const filter = parseFilters(req.query, organizationId);

    if (format) {
      const total = await AuditLog.countDocuments(filter);
      const filename = `audit-logs-${organizationId}.${format}`;
      if (total > LARGE_EXPORT_THRESHOLD) {
        if (!dataExportQueue.isActive) {
          return sendError(
            res,
            503,
            "Background export processing is unavailable.",
          );
        }
        const exportRecord = await AuditLogExport.create({
          organization: organizationId,
          requestedBy: req.user.id || req.user._id,
          format,
          filters: {
            action: req.query.action || undefined,
            startDate: req.query.startDate || undefined,
            endDate: req.query.endDate || undefined,
          },
          expiresAt: new Date(Date.now() + EXPORT_TTL_MS),
        });
        await dataExportQueue.add("audit-log-export", {
          exportId: exportRecord._id.toString(),
        });
        return sendSuccess(
          res,
          {
            export: {
              id: exportRecord._id,
              status: exportRecord.status,
              statusUrl: `/api/organizations/${organizationId}/audit-log-exports/${exportRecord._id}`,
              downloadUrl: `/api/organizations/${organizationId}/audit-log-exports/${exportRecord._id}/download`,
            },
          },
          "Audit log export queued.",
          202,
        );
      }

      res.setHeader(
        "Content-Type",
        format === "csv"
          ? "text/csv; charset=utf-8"
          : "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      );
      res.setHeader(
        "Content-Disposition",
        `attachment; filename="${filename}"`,
      );
      if (format === "csv") return streamCsvExport(res, filter);
      return streamXlsxExport(res, filter);
    }

    // Execute query with pagination and populate the actor
    const logs = await AuditLog.find(filter)
      .populate("actor", "name email profilePic")
      .sort({ createdAt: -1 })
      .skip(skip)
      .limit(limitNum)
      .lean();

    const total = await AuditLog.countDocuments(filter);

    sendSuccess(res, {
      logs,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        pages: Math.ceil(total / limitNum),
      },
    });
  } catch (error) {
    console.error("❌ Error fetching audit logs:", error);
    sendError(res, 500, "Server error fetching audit logs.");
  }
};

export const getAuditLogExport = async (req, res) => {
  try {
    const exportRecord = await AuditLogExport.findOne({
      _id: req.params.exportId,
      organization: req.params.id,
    }).lean();
    if (!exportRecord)
      return sendError(res, 404, "Audit log export not found.");
    return sendSuccess(res, {
      export: {
        id: exportRecord._id,
        status: exportRecord.status,
        downloadUrl:
          exportRecord.status === "completed"
            ? `/api/organizations/${req.params.id}/audit-log-exports/${exportRecord._id}/download`
            : null,
        expiresAt: exportRecord.expiresAt,
        error:
          exportRecord.status === "failed" ? exportRecord.error : undefined,
      },
    });
  } catch (error) {

    return sendError(res, 500, "Server error fetching audit log export.");
  }
};

export const downloadAuditLogExport = async (req, res) => {
  try {
    const exportRecord = await AuditLogExport.findOne({
      _id: req.params.exportId,
      organization: req.params.id,
      status: "completed",
    }).lean();
    if (!exportRecord)
      return sendError(res, 404, "Completed audit log export not found.");
    const filePath = path.join(
      AUDIT_EXPORT_DIRECTORY,
      exportRecord.fileName || "",
    );
    if (
      !exportRecord.fileName ||
      !filePath.startsWith(AUDIT_EXPORT_DIRECTORY + path.sep) ||
      !fs.existsSync(filePath)
    ) {
      return sendError(res, 404, "Audit log export file not found.");
    }
    return res.download(filePath, `audit-logs.${exportRecord.format}`);
  } catch (error) {

    return sendError(res, 500, "Server error downloading audit log export.");
  }
};

/**
 * Meeting Controller — HTTP layer only.
 *
 * Responsibilities:
 *  1. Parse and validate the incoming HTTP request (using Zod schemas).
 *  2. Delegate all business logic to MeetingService.
 *  3. Shape and send the HTTP response.
 *  4. Forward any error to the global error handler via next(err).
 *
 * This file intentionally contains NO database queries, NO AI calls, and
 * NO direct references to external APIs.  All of that lives in
 * server/services/MeetingService.js.
 */

import fs from "fs";
import path from "path";
import { z } from "zod";
import Meeting from "../models/meetingModel.js"; // eslint-disable-line no-unused-vars
import * as MeetingService from "../services/MeetingService.js";
import { ValidationError, UnauthorizedError } from "../utils/errors.js";
import AuditService from "../services/AuditService.js";
import { sendSuccess } from "../utils/responseHandler.js";
import {
  pushMeetingToIntegrations,
  deleteMeetingFromIntegrations,
} from "../services/calendarSyncService.js";  

// ═══════════════════════════════════════════════════════════════
// Zod validation schemas
// ═══════════════════════════════════════════════════════════════

const createMeetingSchema = z.object({
  title: z.string().min(1, "Meeting title is required"),
  description: z.string().optional().default(""),
  meetingType: z
    .enum(["conference", "policy", "event", "internal", "external", "board"])
    .optional()
    .default("conference"),
  date: z.string().optional(),
  time: z.string().optional().default(""),
  duration: z.number().nullable().optional(),
  location: z.string().optional().default(""),
  venue: z.string().optional().default(""),
  participants: z.array(z.record(z.unknown())).optional().default([]),
  agendaItems: z.array(z.record(z.unknown())).optional().default([]),
  policyDetails: z.record(z.unknown()).nullable().optional(),
  recordingType: z.enum(["upload", "live"]).optional().default("upload"),
});

const uploadMeetingSchema = z.object({
  title: z.string().optional(),
  date: z.string().optional(),
  meetingType: z
    .enum(["conference", "policy", "event", "internal", "external", "board"])
    .optional(),
});

const summarizeMeetingSchema = z.object({
  meetingId: z.string().optional(),
  transcript: z.string().optional(),
  date: z.string({ required_error: "Meeting date is required." }),
  title: z.string().optional(),
});

const updateMeetingSchema = z.object({
  title: z.string().min(1).optional(),
  description: z.string().optional(),
  meetingType: z
    .enum(["conference", "policy", "event", "internal", "external", "board"])
    .optional(),
  date: z.string().optional(),
  time: z.string().optional(),
  duration: z.number().nullable().optional(),
  location: z.string().optional(),
  venue: z.string().optional(),
  tags: z.array(z.string()).optional(),
});

const searchMeetingSchema = z.object({
  query: z.string().optional(),
  audioUrl: z.string().url().optional(),
});

const notifyLiveMeetingSchema = z.object({
  roomId: z.string().min(1, "roomId is required"),
  participants: z
    .array(z.object({ name: z.string(), email: z.string().optional() }))
    .min(1, "At least one participant is required"),
});

const getAllMeetingsQuerySchema = z.object({
  page: z
    .string()
    .optional()
    .transform((val) => {
      if (!val) return 1;
      const parsed = parseInt(val, 10);
      return isNaN(parsed) || parsed < 1 ? 1 : parsed;
    }),
  limit: z
    .string()
    .optional()
    .transform((val) => {
      if (!val) return 10;
      const parsed = parseInt(val, 10);
      if (isNaN(parsed) || parsed < 1) return 10;
      return parsed > 100 ? 100 : parsed; // Cap at 100
    }),
  search: z.string().optional(),
  meetingType: z.string().optional(),
  includeArchived: z
    .string()
    .optional()
    .transform((val) => val === "true"),
});

// Helper to prevent path traversal in manual file cleanup checks
const validatePath = (filePath) => {
  if (!filePath) throw new Error("Path is required");
  const resolved = path.resolve(filePath);
  const uploadsDir = path.resolve("uploads");
  if (!resolved.startsWith(uploadsDir)) {
    throw new Error("Directory traversal detected: Access denied");
  }
  return resolved;
};

// ── Helper: extract userId from the request ───────────────────
const getUserId = (req) => {
  const id = req.user?.id || req.user?._id;
  if (!id) throw new UnauthorizedError();
  return id.toString();
};

// ═══════════════════════════════════════════════════════════════
// Controller handlers
// ═══════════════════════════════════════════════════════════════

/* ─────────────────────────────────────────────────────────────
   1. CREATE MEETING (Schedule from CreateMeeting form)
   Used by: CreateMeeting.jsx "Schedule Meeting" section
   ───────────────────────────────────────────────────────────── */
export const createMeeting = async (req, res, next) => {
  try {
    const uploaderId = getUserId(req);

    let validated;
    try {
      validated = createMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr); // ZodError → errorHandler → 400
    }

    const meeting = await MeetingService.createMeeting(
      uploaderId,
      req.user?.organization || null,
      validated,
    );

    if (req.body.syncToCalendar) {
      pushMeetingToIntegrations(uploaderId, meeting).catch(console.error);
    }

    return sendSuccess(
      res,
      {
        meeting: {
          _id: meeting._id,
          title: meeting.title,
          meetingType: meeting.meetingType,
          date: meeting.date,
        },
      },
      "Meeting scheduled successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   2. UPLOAD MEETING (Original - from UploadMeeting page)
   Used by: UploadMeeting.jsx
   ───────────────────────────────────────────────────────────── */
export const uploadMeeting = async (req, res, next) => {
  const uploadedFilePath = req.file?.path || null;

  try {
    if (!req.file) {
      throw new ValidationError("No audio file uploaded.");
    }
    const uploaderId = getUserId(req);

    let validated;
    try {
      validated = uploadMeetingSchema.parse(req.body);
    } catch (zodErr) {
      // Clean up the uploaded file on validation failure before routing
      if (uploadedFilePath) {
        try {
          const safePath = validatePath(uploadedFilePath);
          if (fs.existsSync(safePath)) {
            fs.unlinkSync(safePath);
          }
        } catch {
          // ignore cleanup errors
        }
      }
      throw zodErr;
    }

    const { meeting, transcript } =
      await MeetingService.uploadAndTranscribeMeeting(
        uploaderId,
        req.user?.organization || null,
        req.file,
        validated,
      );

    return sendSuccess(
      res,
      {
        meetingId: meeting._id,
        transcript,
      },
      "Meeting transcribed successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   3. UPLOAD AUDIO FOR EXISTING MEETING
   Used by: CreateMeeting.jsx "Upload Meeting" section
   ───────────────────────────────────────────────────────────── */
export const uploadAudioForMeeting = async (req, res, next) => {
  try {
    if (!req.file) {
      throw new ValidationError("No audio file uploaded.");
    }
    const uploaderId = getUserId(req);
    const { meetingId } = req.body;

    if (!meetingId) {
      throw new ValidationError("Meeting ID is required");
    }

    const { meeting, transcript } =
      await MeetingService.uploadAudioForExistingMeeting(
        uploaderId,
        meetingId,
        req.file,
      );

    return sendSuccess(
      res,
      {
        meetingId: meeting._id,
        transcript,
      },
      "Audio uploaded and transcribed successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   4. SUMMARIZE MEETING (Generate AI MOM)
   Used by: UploadMeeting.jsx and CreateMeeting.jsx
   ───────────────────────────────────────────────────────────── */
export const summarizeMeeting = async (req, res, next) => {
  try {
    const userId = getUserId(req);

    let validated;
    try {
      validated = summarizeMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr);
    }

    const result = await MeetingService.generateMeetingMoM(
      userId,
      validated.meetingId || null,
      validated.transcript || "",
      validated.date,
      validated.title || null,
    );

    if (result.queued) {
      return sendSuccess(
        res,
        null,
        "Minutes generation started in the background. Please wait...",
        202,
      );
    }

    return sendSuccess(
      res,
      {
        mom: result.mom,
        momText: result.momText,
        meetingId: result.meetingId,
      },
      "Minutes generated successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   5. GET ALL MEETINGS (Dashboard)
   Used by: Dashboard / Summaries page
   ───────────────────────────────────────────────────────────── */
export const getAllMeetings = async (req, res, next) => {
  try {
    const userId = getUserId(req);

    let validatedQuery;
    try {
      validatedQuery = getAllMeetingsQuerySchema.parse(req.query);
    } catch (zodErr) {
      return next(zodErr);
    }

    const { meetings, pagination } = await MeetingService.getAllMeetings(
      userId,
      req.user?.organization || null,
      validatedQuery,
    );

    return sendSuccess(res, { meetings, pagination });
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   6. DELETE MEETING
   ───────────────────────────────────────────────────────────── */
export const deleteMeeting = async (req, res, next) => {
  try {
    await MeetingService.deleteMeeting(
      req.doc || null, // from requireOwnerOrAdmin middleware (may be undefined)
      req.params.id,
    );

    if (req.doc && req.doc.organization) {
      AuditService.logAction({
        actorId: getUserId(req),
        action: "MEETING_DELETED",
        entity: "Meeting",
        entityId: req.doc._id,
        organizationId: req.doc.organization,
        details: { title: req.doc.title },
      });
    }

    return sendSuccess(res, null, "Meeting deleted successfully");
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   7. GET MEETING BY ID
   Used by: MeetingDetails.jsx
   ───────────────────────────────────────────────────────────── */
export const getMeetingById = async (req, res, next) => {
