export const initListeners = (io) => {
  if (!io) {
    console.warn("⚠️ initListeners: Socket.IO instance is not provided.");
    return;
  }

  // ─────────────────────────────────────────────────────────────
  // MEETINGS
  // ─────────────────────────────────────────────────────────────

  eventBus.on("meeting.created", async ({ meeting, membersToNotify = [] }) => {
    for (const membership of membersToNotify) {
      const formattedNotification = await createNotification(
        membership.user._id,
        "New Meeting Scheduled",
        `A new meeting "${meeting.title}" has been scheduled.`,
        "meetings",
        `/meeting/${meeting._id}`,
        "View Details",
      );
      if (formattedNotification) {
        io.to(membership.user._id.toString()).emit(
          "notification:new",
          formattedNotification,
        );
      }
    }
  });

  // ─────────────────────────────────────────────────────────────
  // MoM / AI PROCESSING
  // ─────────────────────────────────────────────────────────────

  eventBus.on("mom.generated", async (meeting) => {
    // Notify the meeting uploader/owner if they exist on the object
    const userId = meeting.uploadedBy || meeting.owner;
    if (userId) {
      const formattedNotification = await createNotification(
        userId,
        "Minutes of Meeting Generated",
        `MoM for "${meeting.title}" is ready.`,
        "ai_processing",
        `/meeting/${meeting._id}`,
        "View MoM",
      );
      if (formattedNotification) {
        io.to(userId.toString()).emit(
          "notification:new",
          formattedNotification,
        );
      }

      // We also emit a specific socket event for the UI to catch
      io.to(userId.toString()).emit("mom-generation-complete", {
        meetingId: meeting._id,
        title: meeting.title,
        summary: meeting.summary,
        mom: meeting.structuredMoM,
      });
    }
  });

  // ─────────────────────────────────────────────────────────────
  // DATA EXPORT
  // ─────────────────────────────────────────────────────────────

  eventBus.on("export.ready", async ({ userId, downloadUrl }) => {
    const formattedNotification = await createNotification(
      userId,
      "Data Export Ready",
      "Your data export has been completed and emailed to you.",
      "system",
      downloadUrl,
      "Download",
    );
    if (formattedNotification) {
      io.to(userId.toString()).emit("notification:new", formattedNotification);
    }
  });

  // ─────────────────────────────────────────────────────────────
  // ORGANIZATIONS
  // ─────────────────────────────────────────────────────────────

  eventBus.on(
    "organization.joined",
    async ({ userId, organizationId, organizationName, adminId }) => {

      if (adminId && adminId.toString() !== userId.toString()) {
        const formattedNotification = await createNotification(
          adminId,
          "New Member Joined",
          `A new user has joined your organization: ${organizationName}.`,
          "organizations",
          "/team-members",
          "View Team",
        );
        if (formattedNotification) {
          io.to(adminId.toString()).emit(
            "notification:new",
            formattedNotification,
          );
        }
      }
    },
  );

  eventBus.on(
    "live_meeting.notified",
    async ({ uploaderId, roomId, participants, orgId }) => {

      for (const user of participants) {
        const formattedNotification = await createNotification(
          user._id,
          "Live Meeting Started",
          "You have been invited to join a live meeting.",
          "meetings",
          `/meeting-room/${roomId}`,
          "Join Now",
        );
        if (formattedNotification) {
          io.to(user._id.toString()).emit(
            "notification:new",
            formattedNotification,
          );
        }
      }
    },
  );

  console.log("✅ Event listeners initialized");
};

import CalendarConnection from "../models/calendarConnectionModel.js";
import Meeting from "../models/meetingModel.js";
import {
  fetchExternalEvents,
  decryptToken, // eslint-disable-line no-unused-vars
  getGoogleOAuth2Client, // eslint-disable-line no-unused-vars
  getMicrosoftClient, // eslint-disable-line no-unused-vars
} from "../services/calendarService.js";
import { google } from "googleapis"; // eslint-disable-line no-unused-vars

/**
 * Background sync job for calendar reconciliation
 * This job periodically fetches external calendar events and syncs them back to MeetOnMemory
 * It handles conflict resolution using a "last modified wins" strategy
 */

const SYNC_INTERVAL_MS = 15 * 60 * 1000; // 15 minutes

let syncIntervalId = null;

/**
 * Sync external calendar events for a specific user and provider
 */
const syncUserCalendar = async (userId, provider) => {
  try {
    const connection = await CalendarConnection.findOne({
      user: userId,
      provider,
      syncStatus: "connected",
    });

    if (!connection) {
      console.log(`No active ${provider} connection for user ${userId}`);
      return;
    }

    // Calculate sync window (last 30 days to next 90 days)
    const timeMin = new Date();
    timeMin.setDate(timeMin.getDate() - 30);

    const timeMax = new Date();
    timeMax.setDate(timeMax.getDate() + 90);

    // Fetch external events
    const externalEvents = await fetchExternalEvents(
      userId,
      timeMin.toISOString(),
      timeMax.toISOString(),
    );

    if (!externalEvents || !externalEvents[provider]) {
      console.log(
        `No external events found for ${provider} for user ${userId}`,
      );
      return;
    }

    const events = externalEvents[provider];
    let syncedCount = 0;
    let conflictCount = 0;

    for (const externalEvent of events) {
      const externalEventId = externalEvent.id;
      const externalEventTitle =
        externalEvent.summary || externalEvent.title || "External Event";
      const externalEventStart =
        externalEvent.start?.dateTime || externalEvent.start?.date;
      const externalEventEnd =
        externalEvent.end?.dateTime || externalEvent.end?.date;
      const externalEventUpdated =
        externalEvent.updated || externalEvent.lastModifiedDateTime;

      // Check if this event is already synced
      const existingMeeting = await Meeting.findOne({
        uploadedBy: userId,
        [`calendarEvents.${provider}.eventId`]: externalEventId,
      });

      if (existingMeeting) {
        // Event already synced - check for updates
        const lastSyncTime =
          existingMeeting.calendarEvents?.[provider]?.syncedAt;

        if (lastSyncTime && externalEventUpdated) {
          const lastModifiedDate = new Date(externalEventUpdated);
          const syncDate = new Date(lastSyncTime);

          // If external event was modified after last sync, update the meeting
          if (lastModifiedDate > syncDate) {
            console.log(
              `Updating meeting ${existingMeeting._id} from ${provider} calendar`,
            );

            existingMeeting.title = externalEventTitle;
            if (externalEventStart)
              existingMeeting.date = new Date(externalEventStart);
            if (externalEvent.description)
              existingMeeting.description = externalEvent.description;

            existingMeeting.calendarEvents[provider].syncedAt = new Date();
            await existingMeeting.save();
            syncedCount++;
          }
        }
      } else {
        // New external event - create a meeting record
        console.log(
          `Creating new meeting from ${provider} event: ${externalEventTitle}`,
        );

        const newMeeting = await Meeting.create({

          uploadedBy: userId,
          title: externalEventTitle,
          description: externalEvent.description || "",
          date: externalEventStart ? new Date(externalEventStart) : new Date(),
          time: externalEventStart
            ? new Date(externalEventStart).toLocaleTimeString([], {
                hour: "2-digit",
                minute: "2-digit",
              })
            : "",
          duration:
            externalEventStart && externalEventEnd
              ? Math.round(
                  (new Date(externalEventEnd) - new Date(externalEventStart)) /
                    60000,
                )
              : null,
          location: externalEvent.location || "",
          calendarEvents: {
            [provider]: {
              eventId: externalEventId,
              syncedAt: new Date(),
            },
          },
          status: "uploaded",
          transcript: "",
          summary: "",
        });

        syncedCount++;
      }
    }

    // Update connection sync status
    connection.lastSyncAt = new Date();
    connection.syncError = null;
    await connection.save();

    console.log(
      `Synced ${syncedCount} events for ${provider} for user ${userId}`,
    );
    return { syncedCount, conflictCount };
  } catch (error) {
    console.error(
      `Error syncing ${provider} calendar for user ${userId}:`,
      error.message,
    );

    // Update connection with error
    try {
      const connection = await CalendarConnection.findOne({
        user: userId,
        provider,
      });
      if (connection) {
        connection.syncStatus = "error";
        connection.syncError = error.message;
        await connection.save();
      }
    } catch (updateError) {
      console.error("Error updating connection status:", updateError.message);
    }

    throw error;
  }
};

/**
 * Sync all connected calendars for all users
 */
const syncAllCalendars = async () => {
  console.log("Starting calendar sync job...");

  try {
    const connections = await CalendarConnection.find({
      syncStatus: "connected",
    });

    if (connections.length === 0) {
      console.log("No active calendar connections to sync");
      return;
    }

    console.log(`Found ${connections.length} active calendar connections`);

    for (const connection of connections) {
      try {
        await syncUserCalendar(connection.user, connection.provider);
      } catch (error) {
        console.error(
          `Failed to sync ${connection.provider} for user ${connection.user}:`,
          error.message,
        );
      }
    }

    console.log("Calendar sync job completed");
  } catch (error) {
    console.error("Error in calendar sync job:", error.message);
  }
};

/**
 * Start the calendar sync job
 */
export const startCalendarSyncJob = () => {
  if (syncIntervalId) {
    console.log("Calendar sync job already running");
    return;
  }

  console.log("Starting calendar sync job (interval: 15 minutes)");

  // Run immediately on start
  syncAllCalendars();

  // Schedule recurring sync
  syncIntervalId = setInterval(syncAllCalendars, SYNC_INTERVAL_MS);
};

/**
 * Stop the calendar sync job
 */
export const stopCalendarSyncJob = () => {
  if (syncIntervalId) {
    clearInterval(syncIntervalId);
    syncIntervalId = null;
    console.log("Calendar sync job stopped");
  }
};

/**
 * Manual trigger for calendar sync (useful for testing)
 */
export const triggerManualSync = async (userId = null, provider = null) => {
  if (userId && provider) {
    return await syncUserCalendar(userId, provider);
  } else {
    return await syncAllCalendars();
  }
};

export default {
  startCalendarSyncJob,
  stopCalendarSyncJob,
  triggerManualSync,
};

import userModel from "../models/userModel.js";
import membershipModel from "../models/membershipModel.js";
import Meeting from "../models/meetingModel.js";
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import jwt from "jsonwebtoken";
import transporter from "../config/nodeMailer.js";
import eventBus from "../services/eventBus.js";
import auditLogExportJob from "./auditLogExportJob.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

export const SENSITIVE_USER_FIELDS = [
  "password",
  "verifyOtp",
  "verifyOtpExpireAt",
  "resetOtp",
  "resetOtpExpireAt",
  "resetPasswordToken",
  "resetPasswordExpires",
  "otp",
  "otpExpires",
  "googleAccessToken",
  "googleRefreshToken",
  "googleId",
  "__v",
];

export const sanitizeUserForExport = (user) => {
  if (!user) return null;
  const sanitized = { ...user };
  for (const field of SENSITIVE_USER_FIELDS) {
    delete sanitized[field];
  }
  return sanitized;
};

export default async function exportDataJob(job, app) {

  if (job.name === "audit-log-export") return auditLogExportJob(job);
  const { userId, email } = job.data;
  console.log(`📦 Starting data export for user ${userId}...`);

  try {
    // Fetch User Data
    const userRaw = await userModel
      .findById(userId)
      .select(
        "-password -verifyOtp -verifyOtpExpireAt -resetOtp -resetOtpExpireAt -googleAccessToken -googleRefreshToken",
      )
      .lean();
    if (!userRaw) throw new Error("User not found");

    const user = sanitizeUserForExport(userRaw);

    // Fetch Meetings
    const meetings = await Meeting.find({ uploadedBy: userId }).lean();

    // Fetch Memberships
    const memberships = await membershipModel.find({ user: userId }).lean();

    const exportDir = path.join(__dirname, "..", "uploads", "exports");
    if (!fs.existsSync(exportDir)) {
      fs.mkdirSync(exportDir, { recursive: true });
    }

    const fileName = `export_${userId}_${Date.now()}.zip`;
    const filePath = path.join(exportDir, fileName);

    // archiver v8+ is a pure ES Module — must be loaded via dynamic import()
    const { default: archiver } = await import("archiver");

    await new Promise((resolve, reject) => {
      const output = fs.createWriteStream(filePath);
      const archive = archiver("zip", { zlib: { level: 9 } });

      output.on("close", resolve);
      archive.on("error", reject);
      archive.on("warning", (err) => {
        if (err.code === "ENOENT") console.warn(err);
        else reject(err);
      });

      archive.pipe(output);
      archive.append(JSON.stringify(user, null, 2), {
        name: "user_profile.json",
      });
      archive.append(JSON.stringify(meetings, null, 2), {
        name: "meetings.json",
      });
      archive.append(JSON.stringify(memberships, null, 2), {
        name: "memberships.json",
      });
      archive.finalize();
    });

    console.log(`✅ Data export for user ${userId} saved to ${filePath}`);

    // Generate Secure Download Link
    const jwtSecret = process.env.JWT_SECRET;
    const downloadToken = jwt.sign({ userId, fileName }, jwtSecret, {
      expiresIn: "24h",
    });

    // In production, BASE_URL should be configured correctly in .env
    const baseUrl = process.env.BASE_URL || "http://localhost:3000";
    const downloadUrl = `${baseUrl}/api/user/download-export/${downloadToken}`;

    // Send Email
    const mailOptions = {
      from: process.env.SMTP_USER || "no-reply@meetonmemory.com",
      to: email,
      subject: "Your Data Export is Ready",
      html: `
        <h2>Data Export Completed</h2>
        <p>Your requested data export is ready. You can download it using the link below:</p>
        <p><a href="${downloadUrl}">Download Data Export</a></p>
        <p><strong>Note:</strong> This link will expire in 24 hours.</p>
      `,
    };

    await transporter.sendMail(mailOptions);
    console.log(`📧 Notification email sent to ${email}`);

    eventBus.emit("export.ready", { userId, downloadUrl });

    return { success: true, fileName };
  } catch (error) {
    console.error(`❌ Data export failed for user ${userId}:`, error.message);
    throw error;
  }
}

import { GoogleGenerativeAI } from "@google/generative-ai"; // eslint-disable-line no-unused-vars
import axios from "axios"; // eslint-disable-line no-unused-vars
import eventBus from "../services/eventBus.js";
import Meeting from "../models/meetingModel.js";
import {
  processStructuredMoM,
  detectResolutions,
} from "../services/knowledgeGraphService.js";
import User from "../models/userModel.js";

import { indexMeeting } from "../utils/embeddingUtils.js";
import {
  generateMoMWithAI,
  normalizeMoM,
  buildHumanReadableMoM,
} from "../services/GenerativeAIService.js";

export default async function processAudioJob(job, app) {

  const { meetingId, transcript, date, title, userId } = job.data;
  const GEMINI_API_KEY = process.env.GEMINI_API_KEY; // eslint-disable-line no-unused-vars
  const GEMINI_MODEL = process.env.GEMINI_MODEL || "gemini-2.5-flash"; // eslint-disable-line no-unused-vars
  const HUGGINGFACE_API_KEY = process.env.HUGGINGFACE_API_KEY; // eslint-disable-line no-unused-vars

  let textToSummarize = (transcript || "").trim();

  // Fetch meeting transcript if only meetingId is provided
  let meeting = null;
  if (meetingId && !textToSummarize) {
    meeting = await Meeting.findById(meetingId);
    if (!meeting) {
      throw new Error("Meeting not found");
    }
    textToSummarize = (meeting.transcript || "").trim();
  }

  if (!textToSummarize) {
    throw new Error("No transcript provided.");
  }

  console.log(`🧠 Generating MoM for ${meetingId || "transcript-only"}...`);

  let structured = null;
  let humanReadable = "";

  structured = await generateMoMWithAI(textToSummarize, date, title);

  if (structured) {
    const mom = normalizeMoM(structured, title, date);
    humanReadable = buildHumanReadableMoM(mom);

    let meetingToUpdate = meeting;

    if (!meetingToUpdate && meetingId) {
      meetingToUpdate = await Meeting.findById(meetingId);
    }

    if (!meetingToUpdate && !meetingId) {
      const user = await User.findById(userId);
      const userOrg = user?.organization || null;

      meetingToUpdate = await Meeting.create({
        uploadedBy: userId,
        organization: userOrg,
        title: mom.title,
        date: new Date(date),
        transcript: textToSummarize,
        summary: humanReadable,
        structuredMoM: mom,
        status: "completed",
      });
      await indexMeeting(meetingToUpdate);
    } else if (meetingToUpdate) {
      meetingToUpdate.title = mom.title;
      meetingToUpdate.date = new Date(date);
      meetingToUpdate.summary = humanReadable;
      meetingToUpdate.structuredMoM = mom;
      await meetingToUpdate.save();
    }

    console.log("✅ MoM saved to database");

    // Trigger internal events for webhooks
    try {
      if (!meetingId) {
        eventBus.emit("meeting.created", {
          meeting: meetingToUpdate,
          membersToNotify: [],
        });
      }
      eventBus.emit("mom.generated", meetingToUpdate);
    } catch (evtErr) {
      console.error(
        "⚠️ Failed to emit webhook events from queue:",
        evtErr.message,
      );
    }

    if (meetingToUpdate) {
      try {
        await detectResolutions(meetingToUpdate, mom);
        await processStructuredMoM(meetingToUpdate, mom);
      } catch (kgError) {
        console.error(
          "⚠️ Knowledge graph processing failed (non-fatal):",
          kgError,
        );
      }
    }

    return { success: true, meetingId: meetingToUpdate?._id };
  }

  throw new Error("No summary generated");
}

import rateLimit from "express-rate-limit";
import { getRedisClient } from "../services/redisService.js";

let RedisStore;
try {
  const mod = await import("rate-limit-redis");
  RedisStore = mod.RedisStore || mod.default;
} catch (e) {

  // rate-limit-redis optional dependency fallback
}

// Create a shared store that uses Redis if available, otherwise falls back to in-memory
const createStore = () => {
  const redisClient = getRedisClient();
  if (redisClient && RedisStore) {
    return new RedisStore({
      sendCommand: (...args) => redisClient.sendCommand(...args),
    });
  }
  return undefined; // Falls back to default MemoryStore
};

// General rate limiter for API routes
export const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: {
    success: false,
    message: "Too many requests from this IP, please try again later.",
  },
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
  store: createStore(),
});

